    ['Mama Mia'] = {
        id = 131,
        start_npc = 'Mamaulabion',
        start_zone = 'Norg',
        start_pos = 'G-6',
        description = 'Mamaulabion would like you to bring him any "thuper-dee-duper, overflowing with thpethial power itemth" you happen to come across in your travels. However, he was not able to provide you with any details on their whereabouts.',
        reward = 'Evoker\'s Ring',
        fame = 'Norg',
        fame_level = '4',
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Mamaulabion at (G-6) in Norg to activate the quest (this does not need to be done before obtaining the seven items).\n2. Obtain the following seven items by selecting them as your reward after defeating the seven avatars below in the battles listed below\n   - Trial by Fire (Ifrit): Egil\'s Torch\n   - Trial by Ice (Shiva): Rust \'B\' Gone\n   - Trial by Wind (Garuda): Bubbly Water\n   - Trial by Earth (Titan): Desert Light\n   - Trial by Lightning (Ramuh): Elder Branch\n   - Trial by Water (Leviathan): Eye of Nept\n   - The Moonlit Path (Fenrir): Ancients\' Key\n3. Return all seven items to Mamaulabion (the items must be traded one at a time and it is not necessary to turn in all seven at once).\n4. Wait until midnight (JST), then speak with Mamaulabion once more to receive the Evoker\'s Ring.\n5. Note that the quest is only repeatable if Evoker\'s Ring is dropped.',
        notes = nil,
    },
    ['Missionary Man'] = {
