    ['Open Sesame'] = {
        id = 165,
        start_npc = 'Lokpix',
        start_zone = 'Eastern Altepa Desert',
        start_pos = 'G-7',
        description = 'There\'s supposedly a way to open that troublesome door in the Quicksand Caves by yourself. If you wish to know the secret, bring back a tremorstone and a meteorite. Should you lack a meteroite, either a soil gem or twelve soil geodes will suffice.',
        reward = '[Key Item] Loadstone',
        fame = 'Outlands',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Tremorstone and one of the following:\n1x Meteorite or 1x Soil Gem or 12x Soil Geode', count = 1},
        },
        walkthrough = '1. Speak to Lokpix in Eastern Altepa Desert at (G-7).  He will request a  Tremorstone in addition to one of the following options:\n   - Meteorite\n     - Dropped by Crawlers in West Sarutabaruta, on Starfall Hillock ().\n     - Awarded in Colonization Reives in Kamihr Drifts (Requires [Key Item] "Fragmenting" from Quest: Breaking the Ice) ().\n     - Awarded in Colonization Reives in Outer Ra\'Kaznar (Requires [Key Item] "Pulverizing" from Quest: Lerene\'s Lament) ().\n     - Gathered in Mog Gardens (Requires Mineral Vein Rank 3).\n   - Soil Gem\n     - Crafted from Goldsmithing.\n   - Soil Geode x12.\n2. You may find Unity Warp 125 to Quicksand Caves helpful to reach the Cloister of Tremors containing the Tremorstone in the west part of the caves.\n3. Trade him the items at the same time to receive your reward.\n   - The [Key Item] Loadstone will allow you to open the weighted doors in Quicksand Caves solo.',
        notes = nil,
    },
    ['Personal Hygiene'] = {
        id = 10,
        start_npc = 'Gatih Mijurabi',
        start_zone = 'Kazham',
        start_pos = 'I-8',
        description = 'The Mithra of Kazham are having a hard time holding in their lunches, thanks to the hideous odor you obtained after getting too close to the blue Rafflesia pollen. The only way to get clean is by taking a long dip in a hot spring located deep beneath the sea.',
        reward = 'Mithran Stone',
        fame = 'Kazham',
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'Even More Gullible\'s Travels'},
        next = nil,
        requirements = nil,
        walkthrough = '1. After completing Even More Gullible\'s Travels you will have a scent of the Rafflesia flowers on you.\n   - This scent will repulse all Mithra in Kazham but is required to start the quest The Opo-opo and I.\n2. Speak to Gatih Mijurabi (I-8) to begin this quest to remove the scent.\n3. The hot springs is located in Korroloka Tunnel (G-9) on map 4.\n4. Stand yourself under the waterfall for approximately 5 minutes.\n   - When you are in the right spot, you will get the message that "The water in this spring is pleasant and tepid. This looks like a nice place to warm yourself up."\n   - When you exit the hot spring after standing under the waterfall for the right amount of time, you will get another message informing you that the smell of the Rafflesia pollen is gone.\n5. The waterfall is guarded by several leeches that aggro to level 99 players.\n6. Return to Gatih Mijurabi to complete the quest.',
        notes = nil,
    },
