        description = 'Planar rifts have been reported in Ru\'Aun Gardens, Ve\'Lugannon Palace, and the Shrine of Ru\'Avitau. Engage the Voidwalkers at each location and obliterate them!',
        reward = nil,
        fame = 'N/A',
