    ['Thanks for All the Fish'] = {
        id = 203,
        start_npc = 'Jourdenaux',
        start_zone = 'Rabao',
        start_pos = 'F-8',
        description = 'Lu Shang\'s fishing rod has a hidden power deep inside, which Jordenaux has offered to draw forth if he deems you worthy--by collecting 60 types of fish and fulfilling all Records of Eminence objectives in the "Fishing (Tenacity)" category.',
        reward = 'Lu Shang\'s Fishing Rod +1',
        fame = 'Outlands',
        fame_level = nil,
        title = 'Fish Whisperer',
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Lu Shang\'s Fishing Rod', count = 1},
        },
        walkthrough = 'You must first complete the First Step Forward Records of Eminence objective\n1. Speak to Jourdenaux while in possession of a Lu Shang\'s Fishing Rod to flag this quest.\n2. This will unlock a new Records of Eminence category "Fishing > Fishing (Tenacity)"\n3. You must now do the following:\n   - Catch 60 different types of fish\n     - You can use any rod to accomplish this.\n     - Catching the fish can be done in tandem to completing the Fishing (Tenacity) objectives, or the fish can have been caught previously.\n     - Use Katsunaga to tell you how many types of fish you have caught so far.\n   - Complete all Fishing (Tenacity) objectives\n     - You must complete all of the objectives under this category using only your Lu Shang\'s Fishing Rod.\n     - Lures to catch multiple fish at once is effective for certain tasks that require many fish.\n4. After completing all of the objectives, trade your Lu Shang\'s Fishing Rod to Jourdenaux to complete the quest and for your reward.',
        notes = nil,
    },
    ['The Firebloom Tree'] = {
        id = 1,
        start_npc = 'Soun Abralah',
        start_zone = 'Kazham',
        start_pos = 'H-9',
        description = 'Journey to the Yuhtunga Jungle and retrieve a piece of firebloom wood from the most fire-resistant side of the Firebloom Tree. To check the most fire-resistant side, you must take a vine from each side of the tree to Ifrit\'s Cauldron for testing.',
        reward = '5,000 Gil',
        fame = 'Kazham',
        fame_level = '6',
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = {
            {name = '[Key Item] Northern vine', count = 1},
            {name = '[Key Item] Eastern vine', count = 1},
            {name = '[Key Item] Southern vine', count = 1},
            {name = '[Key Item] Western vine', count = 1},
            {name = '[Key Item] Firebloom Tree wood', count = 1},
        },
        walkthrough = '1. Soun Abralah needs a piece of unburnable wood from the Firebloom Tree.\n2. Visit the Firebloom Tree Roots at Yuhtunga Jungle (H-9)\n   - Survival Guide or Outpost warp and head northeast\n3. Harvest the Eastern vine, Northern vine, Western vine, and Southern vine by clicking on the trees\n   - No Hatchets required\n   - The Western vine is in the tunnel.\n4. Head to Ifrit\'s Cauldron to test the vines\' fire resistance in the Flame Spouts.\n   - You need to touch 3 Flame Spouts\n   - Recommended to use the Survival Guide warp, then go K -> L -> H -> Ash Dragon area.\n5. Return to the appropriate Firebloom Tree Root (only one will work, and it will match your remaining Key Item) and obtain wood\n   - Again, no Hatchet is required.\n6. Return to Soun Abralah for your reward.',
        notes = nil,
    },
