        start_npc = 'Datta',
        start_zone = 'Rabao',
        start_pos = 'F-7',
        description = 'You have been asked to participate in a tour planned by Datta. Travel to the cliff inside the entrance to the Kuftal Tunnel with a party of two or more people of level forty or less, then meet with Datta\'s partner, Hawk Nose.',
        reward = '8,000 gil',
        fame = 'Rabao',
        fame_level = nil,
        title = 'Kuftal Tourist',
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Datta to begin this quest.\n2. Form a party with at least two people who are below level 40.\n   - Alter egos and fellows do not count toward the requirements.\n   - Level sync does work\n3. Head to Kuftal Tunnel and examine the ??? near the entrance for a cutscene.\n   - If you purchase a chocobo in Rabao you can cross the desert without having to worry about aggro.\n   - The Survival Guide also puts you right at the entrance.\n   - The only monsters near the ??? are Lizards who do not aggro at all.\n4. Once you get the cutscene in Kuftal Tunnel, return to Datta for your reward.',
        notes = 'Similar to When Wills Collide and Mercenary Camp, this CS displays fellow party members, a very rare occurrence.\n1. You and your party members overlook the Kuftal tunnel. It\'s not much of a different angle than you\'d see in game.\n2. You can watch this CS again with the Goblin Footprint after returning to Datta\nOriginally this quest required 6 players, but was dropped to 2 with the June 2015 Update',
    },
