    ['The Search for Goldmane'] = {
        id = 200,
        start_npc = 'Zoriboh',
        start_zone = 'Rabao',
        start_pos = 'F-6',
        description = 'How is little Sanctia doing? Zoriboh wants you to take her a present from her father and see that she is keeping out of trouble.',
        reward = 'Deluxe Carbine\n3,000 gil',
