        fame_level = nil,
        title = 'Rookie Hero Instructor',
        repeatable = 'No',
        previous = {'Chasing Dreams'},
        next = nil,
        requirements = {
            {name = 'Copper Key', count = 1},
        },
        walkthrough = '1. Talk to Zoriboh and obtain Care package key item.\n2. Speak to Quelveuiat (I-10) in Tavnazian Safehold.\n3. Go to Riverne - Site A01 and go through the portals to the island at I-11. You will receive a cutscene upon reaching the island.\n4. Trade a Copper Key to the Trunk for another cutscene.\n   - Copper Key drops from Riverne Vulture in Riverne - Site A01.\n5. Travel to the Metalworks and talk to Vladinek (H-8).\n6. Go to Bibiki Bay and take the Manaclipper to Purgonorgo Isle.\n   - You can also use the Voidwatch teleport if you have Bismarck access.\n7. Go to F-9 by the Weathered Boat.\n8. Click the boat for a cutscene.  After the cutscene the NM Rohemolipaud will spawn.\n   - He will use Eagle Eye Shot.\n   - Eventually, he will use Camouflage and the fight will end.\n   - If in a party with multiple players that need the quest, there is a 3 minute wait between respawning the NM.\n9. Click the Weathered Boat again to recieve a cutscene and a Deluxe Carbine.\n10. Go back to Rabao and talk to Zoriboh to complete the quest, and for your 3,000 gil reward.',
        notes = nil,
    },
    ['Trial by Fire'] = {
        id = 12,
        start_npc = 'Ronta-Onta',
        start_zone = 'Kazham',
        start_pos = 'J-9',
        description = 'Ring the tuning fork of fire upon the protocrystal in Ifrit\'s Cauldron. A path will open to the trial that awaits.',
        reward = 'Ifrit (Avatar)\n10,000 gil\nIfrit\'s Blade\nFire Belt\nFire Ring\nEgil\'s Torch',
        fame = 'Kazham',
        fame_level = '6',
        title = 'Heir of the Great Fire',
        repeatable = 'Yes',
        previous = nil,
        next = {
            'The Moonlit Path',
            'Mama Mia',
        },
        requirements = nil,
        walkthrough = '1. Speak with Ronta-Onta to obtain quest. If you are positive that you have the required fame but he is not allowing you to undertake this quest, continue speaking with him until his text changes. Once you have received the key item: Tuning fork of fire, you can now safely undertake the quest.\n2. Travel to Yhoator Jungle and look for the entrance to Ifrit\'s Cauldron at (I-6). On the first map of Ifrit\'s Cauldron head to the Flame Spout at (H-6). Trade it an Ice Cluster to make it recede or wait for it to recede on its own, then continue to (F-6).  On the second map (Map B), go to (I-8) to drop down to the seventh map.  When you land (Map C) go to the drop at (H-7), then proceed to (G-6) to find the entrance to the Cloister of Flames.\n   - Preferably, home point to Ifrit\'s Cauldron #1. If you don\'t have it yet, make sure to grab it on the way.\n   - The Unity 125 warp places you within a short run to the home point. Go left to J follow the tunnel and walk off the ledge at the end of it (the north part of the middle area).\n3. Defeat Ifrit Prime and you will receive a key item: Whisper of flames\n4. Return to Ronta-Onta with the whisper and he will provide several reward options including the ability to summon Ifrit.',
        notes = '1. Up to 6 party members can enter the arena.\n2. Each party member must have their own Tuning fork of fire.\n3. Time limit is 30 minutes.\n4. You can only select one of the rewards Ronta-Onta offers at any time.\n5. You may repeat this quest once per Earth day.\n6. You can save yourself a lot of time traveling to the Cloister by using the Mini Fork of Fire given by the quest Trial-Size Trial by Fire. You must be on Summoner as your main job, and obtain the Mini Tuning Fork from Dodmos, trade the fork back to Dodmos, but enter the Protocrystal normally. So long as you do not clear the level 20 version of the BC, you may warp to the Cloister as many times as you wish. (...or you can use Home Point warps, because it\'s the future.)\n7. You may also choose to retain the whisper in order to complete the requirements for this quest: The Moonlit Path.',
    },
